const { withXcodeProject } = require("expo/config-plugins");

// Free Apple Developer team that already signs the other Expo builds on this Mac
// (security find-identity → "Apple Development: erlin.hx@icloud.com").
const DEVELOPMENT_TEAM = "T29NU9NCA2";
const BUNDLE_ID = "xyz.streamarena.app";

// Sets the Apple Development team + automatic signing on the app target so that
// `expo run:ios --device` (and any prebuild) produces a device-installable build
// without anyone opening Xcode. mobile/ios is git-ignored / regenerated by
// prebuild, so this plugin is the durable home for the signing config.
module.exports = function withSigning(config) {
  return withXcodeProject(config, (cfg) => {
    const project = cfg.modResults;
    const configs = project.pbxXCBuildConfigurationSection();
    for (const key of Object.keys(configs)) {
      const buildConfig = configs[key];
      const settings = buildConfig && buildConfig.buildSettings;
      if (!settings) continue;
      // Only the app target carries the bundle id; skip Pods/project configs.
      if (settings.PRODUCT_BUNDLE_IDENTIFIER !== BUNDLE_ID) continue;
      settings.DEVELOPMENT_TEAM = DEVELOPMENT_TEAM;
      settings.CODE_SIGN_STYLE = "Automatic";
    }
    return cfg;
  });
};
